import{c as o,Q as t,j as a,m as r}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"How do I reset my MFA?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/account/reset-mfa.md","filePath":"guide/recipes/account/reset-mfa.md","lastUpdated":1779094756000}'),n={name:"guide/recipes/account/reset-mfa.md"};function i(s,e,l,c,d,u){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="how-do-i-reset-my-mfa" tabindex="-1">How do I reset my MFA? <a class="header-anchor" href="#how-do-i-reset-my-mfa" aria-label="Permalink to &quot;How do I reset my MFA?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p>You can remove your <strong>own</strong> MFA methods. An <strong>Owner</strong> or <strong>Admin</strong> can clear another user&#39;s MFA so they can re-enrol.</p></div><p>If you lose your phone or hardware key, you&#39;ll need an Owner or Admin to clear the MFA on your account — you can&#39;t do it yourself without a working second factor.</p><h2 id="on-your-own-account" tabindex="-1">On your own account <a class="header-anchor" href="#on-your-own-account" aria-label="Permalink to &quot;On your own account&quot;">​</a></h2><ol><li>Sign in (you&#39;ll need a working second factor or a backup code).</li><li>Open <strong>Account → Security → Authentication Methods</strong>.</li><li>Click <strong>Remove</strong> on the method you want to drop.</li><li>Confirm.</li></ol><h2 id="for-another-user-owner-or-admin" tabindex="-1">For another user (Owner or Admin) <a class="header-anchor" href="#for-another-user-owner-or-admin" aria-label="Permalink to &quot;For another user (Owner or Admin)&quot;">​</a></h2><ol><li>Open <strong>Users</strong> in the customer portal sidebar.</li><li>Open the user&#39;s row.</li><li>Click <strong>Clear MFA</strong> in the actions menu.</li><li>Confirm.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The user signs in once without MFA. If your organisation <a href="./../portal/enforce-mfa">requires MFA</a>, they&#39;re walked through enrolment immediately — they can&#39;t reach the rest of the portal until a new method is on file.</p><div class="warning custom-block"><p class="custom-block-title">Backup codes</p><p>Always print or save the backup codes shown when you first enrolled. They let you sign in without an admin reset.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./enroll-authenticator">How do I enroll an authenticator app?</a></li><li><a href="./add-passkey">How do I add a passkey?</a></li></ul>',12)])])}const p=o(n,[["render",i]]);export{m as __pageData,p as default};
